			break;

			case RTVECTOR:
			break;

			case RTNATLANGUAGE:
			break;

			case RTSCOPE:
			break;

			case RTREUSEWHERE:
			break;

			case RTINTERNALPROP:
				NDR_CHECK(ndr_pull_wsp_cinternalpropertyrestriction(ndr, NDR_BUFFERS, &r->internalpropertyrestriction));
			break;

			case RTPHRASE:
				NDR_CHECK(ndr_pull_wsp_cnoderestriction(ndr, NDR_BUFFERS, &r->phraserestriction));
			break;

			case RTCOERCE_ABSOLUTE:
