			break;

			case RTPROB:
			break;

			case RTFEEDBACK:
			break;

			case RTRELDOC:
				NDR_CHECK(ndr_pull_wsp_creldocrestriction(ndr, NDR_BUFFERS, &r->reldocrestriction));
